VALUES
  ('optician-moex-02349', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有一鏡片，它的度數為-6.00DS/-2.00DC×030，此鏡片和下列那個鏡片是同一度數？', '["-8.00DS/-2.00DC×120", "+8.00DS/+2.00DC×120", "-8.00DS/+2.00DC×030", "-8.00DS/+2.00DC×120"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02350', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '運用鏡片度數儀檢測鏡片度數時，通常其檢測的度數為下列何者？', '["前頂點度數（front vertex power）", "後頂點度數（back vertex power）", "近似度數（approximate power）", "有效度數（effective power）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02351', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '當你用鏡片驗度儀檢測一副眼鏡，發覺其光學中心點不在十字標線的中心點上，則這鏡片有下列何種效 果？', '["圓柱鏡", "稜鏡", "球圓柱鏡", "正鏡片"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02352', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關裂隙片驗光，下列何者錯誤？', '["決定受檢者的散光狀態", "可用於受檢者無法理解其他的自覺式驗光法", "可以知道受檢者潛在可能的視力", "如果受檢者是不規則的散光就無法適用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02353', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受檢者35歲，透過視網膜檢影鏡得到矯正度數，再進行傑克森交叉圓柱鏡檢查，下列敘述何者錯誤？', '["如果散光的度數愈高，散光軸度的精準度對清晰程度的影響就愈小", "決定散光度數時，會把交叉圓柱鏡的其中一個軸度與目前散光的軸度形成相差90度", "如果受檢者回應，交叉圓柱鏡的紅點軸與綜合驗光儀的負圓柱鏡軸度一致時，影像比較清楚，那麼表 示綜合驗光儀的負圓柱鏡的度數應該再增加-0.25 D", "負圓柱鏡的度數每增加-0.50 D，就應該增加+0.25 D的球面鏡（或者減去-0.25 D的球面鏡），以維持等 效球鏡度（spherical equivalent）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02354', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受檢者接受鐘面圖形檢查（clock chart）時，下列敘述何者最不適當？', '["受檢者表示每一條線都差不多，那麼這個檢查就可以結束", "受檢者表示3到9點鐘方向的線是最清晰的，那麼應該在90度的方向增加-0.25 D的圓柱鏡度數", "受檢者表示1到7點鐘方向與2到8點鐘方向的線是最清晰的，那麼應該在大約45度的方向增加-0.25 D 的圓柱鏡度數", "受檢者表示4到10點鐘方向的線是最清晰的，那麼應該在大約60度的方向增加-0.25 D的圓柱鏡度數"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02355', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關針孔視力（pinhole visual acuity）的敘述，下面那一項最不適當？', '["當測量遠距離矯正視力劣於20/30時或更差時，就需要考慮使用", "使用2 mm直徑大小的針孔版，效果較好", "利用增加焦深（depth of focus）效應，來減少視網膜模糊（retinal blur）", "橫切色散像差（transverse chromatic aberration）可能對針孔視力測量影響不大"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02356', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關傑克森交叉圓柱鏡檢測散光的敘述，下列何者正確？', '["為避免受檢者調節能力影響檢查結果，傑克森交叉圓柱鏡檢查時球面鏡片需加上+1.00 D～+2.00 D來霧視", "低視力的受檢者需用±0.25 D的傑克森交叉圓柱鏡來檢測", "一般而言，傑克森交叉圓柱鏡對散光測試的精確度比鐘面圖（clock dial test）來得差", "在進行散光度數（cylinder power refinement）的微調時，傑克森交叉圓柱鏡軸度要放在初步檢查時得到 的散光軸度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02357', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '以鐘面圖或輻射散光圖表（radial line test）檢查時，受檢者表示3點鐘的線條最清楚，而4點鐘的線又較', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02358', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '點鐘的線黑一些，其負散光的軸度最可能為下列何者？', '["180", "100", "080", "110"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
